create table ai_review_proto (created_date timestamp(6), id bigint generated by default as identity (start with 1), last_modified_date timestamp(6), tm_text_unit_variant_id bigint unique, run_name varchar(32), json_review text, primary key (id), constraint UK__AI_REVIEW_PROTO__RUN_NAME__TM_TEXT_UNIT_VARIANT_ID unique (run_name, tm_text_unit_variant_id));
create table ai_translate_automation_config (enabled boolean not null, source_text_max_count_per_locale integer not null, created_date timestamp(6), id bigint generated by default as identity (start with 1), last_modified_date timestamp(6), cron_expression varchar(255), repository_ids_json text, primary key (id));
create table ai_translate_locale_prompt_suffix (created_date timestamp(6), id bigint generated by default as identity (start with 1), last_modified_date timestamp(6), locale_id bigint not null, prompt_suffix text not null, primary key (id), constraint UK__AI_TRANSLATE_LOCALE_PROMPT_SUFFIX__LOCALE__ID unique (locale_id));
create table ai_translate_run (estimated_cost_usd numeric(18,6), source_text_max_count_per_locale integer not null, cached_input_tokens bigint not null, created_date timestamp(6), finished_at timestamp(6), id bigint generated by default as identity (start with 1), input_tokens bigint not null, last_modified_date timestamp(6), output_tokens bigint not null, pollable_task_id bigint unique, reasoning_tokens bigint not null, repository_id bigint not null, requested_by_user_id bigint, started_at timestamp(6), status varchar(32) not null check (status in ('SCHEDULED','RUNNING','COMPLETED','FAILED','PARTIAL')), trigger_source varchar(32) not null check (trigger_source in ('MANUAL','CRON')), related_strings_type varchar(64) not null, translate_type varchar(64) not null, model varchar(255) not null, primary key (id));
create table ai_translate_text_unit_attempt (ai_translate_run_id bigint, created_date timestamp(6), id bigint generated by default as identity (start with 1), last_modified_date timestamp(6), locale_id bigint not null, pollable_task_id bigint not null, tm_text_unit_id bigint not null, tm_text_unit_variant_id bigint, status varchar(32) not null, translate_type varchar(64) not null, request_payload_blob_name varchar(1024), response_payload_blob_name varchar(1024), completion_id varchar(255), error_message text, model varchar(255), request_group_id varchar(255) not null, primary key (id));
create table application_cache (cache_type_id smallint not null, created_date timestamp(6), expiry_date timestamp(6), id bigint generated by default as identity (start with 1), key_md5 varchar(32), value bytea, primary key (id), constraint UK__APPLICATION_CACHE__CACHE_TYPE_ID__KEY_MD5 unique (cache_type_id, key_md5));
create table application_cache_type (id smallint generated by default as identity (start with 1), name varchar(255), primary key (id));
create table asset (deleted boolean not null, "virtual" boolean not null, created_by_user_id bigint, created_date timestamp(6), id bigint generated by default as identity (start with 1), last_modified_date timestamp(6), last_successful_asset_extraction_id bigint unique, repository_id bigint not null, path varchar(255) not null, primary key (id), constraint UK__ASSET__REPOSITORY_ID__PATH unique (repository_id, path));
create table asset_content (extracted_content boolean, asset_id bigint, branch_id bigint, created_date timestamp(6), id bigint generated by default as identity (start with 1), last_modified_date timestamp(6), content_md5 varchar(32), content text not null, primary key (id));
create table asset_extraction (asset_content_id bigint, asset_id bigint, created_by_user_id bigint, created_date timestamp(6), id bigint generated by default as identity (start with 1), last_modified_date timestamp(6), pollable_task_id bigint unique, version bigint, content_md5 varchar(32), filter_options_md5 varchar(32), primary key (id));
create table asset_extraction_by_branch (deleted boolean not null, asset_extraction_id bigint, asset_id bigint, branch_id bigint, created_date timestamp(6), id bigint generated by default as identity (start with 1), last_modified_date timestamp(6), primary key (id), constraint UK__ASSET_EXTRACTION_BY_BRANCH__ASSET_ID__BRANCH unique (asset_id, branch_id));
create table asset_integrity_checker (id bigint generated by default as identity (start with 1), repository_id bigint not null, asset_extension varchar(255) not null, integrity_checker_type varchar(255) not null check (integrity_checker_type in ('MESSAGE_FORMAT','FLUENT','MESSAGE_FORMAT_DOUBLE_BRACES','PRINTF_LIKE','SIMPLE_PRINTF_LIKE','PRINTF_LIKE_IGNORE_PERCENTAGE_AFTER_BRACKETS','PRINTF_LIKE_VARIABLE_TYPE','PRINTF_LIKE_ADD_PARAMETER_SPECIFIER','COMPOSITE_FORMAT','WHITESPACE','TRAILING_WHITESPACE','HTML_TAG','ELLIPSIS','BACKQUOTE','EMPTY_TARGET_NOT_EMPTY_SOURCE','MARKDOWN_LINKS','PYTHON_FPRINT','EMAIL','URL','FORBIDS_CONTROL_CHARACTERS','MISC_AI_TRANSLATE')), primary key (id));
create table asset_integrity_checker_aud (rev integer not null, revend integer, revtype smallint, id bigint not null, repository_id bigint, asset_extension varchar(255), integrity_checker_type varchar(255) check (integrity_checker_type in ('MESSAGE_FORMAT','FLUENT','MESSAGE_FORMAT_DOUBLE_BRACES','PRINTF_LIKE','SIMPLE_PRINTF_LIKE','PRINTF_LIKE_IGNORE_PERCENTAGE_AFTER_BRACKETS','PRINTF_LIKE_VARIABLE_TYPE','PRINTF_LIKE_ADD_PARAMETER_SPECIFIER','COMPOSITE_FORMAT','WHITESPACE','TRAILING_WHITESPACE','HTML_TAG','ELLIPSIS','BACKQUOTE','EMPTY_TARGET_NOT_EMPTY_SOURCE','MARKDOWN_LINKS','PYTHON_FPRINT','EMAIL','URL','FORBIDS_CONTROL_CHARACTERS','MISC_AI_TRANSLATE')), primary key (rev, id));
create table asset_text_unit (do_not_translate boolean not null, asset_extraction_id bigint, branch_id bigint, created_by_user_id bigint, created_date timestamp(6), id bigint generated by default as identity (start with 1), last_modified_date timestamp(6), plural_form_id bigint, content_md5 varchar(32), md5 varchar(32), name varchar(4000), comment text, content text, plural_form_other text, primary key (id), constraint UK__ASSET_TEXT_UNIT__MD5__ASSET_EXTRACTION_ID unique (md5, asset_extraction_id));
create table asset_text_unit_to_tm_text_unit (asset_extraction_id bigint, asset_text_unit_id bigint, id bigint generated by default as identity (start with 1), tm_text_unit_id bigint, primary key (id), constraint UK__ASSET_TEXT_UNIT_TO_TM_TEXT_UNIT__ASSET_TEXT_UNIT_ID unique (asset_text_unit_id));
create table asset_text_unit_usages (asset_text_unit_id bigint not null, usages varchar(255));
create table authority (created_by_user_id bigint, created_date timestamp(6), id bigint generated by default as identity (start with 1), last_modified_date timestamp(6), user_id bigint not null, authority varchar(255), primary key (id), constraint UK__AUTHORITIES__USER_ID__AUTHORITY unique (user_id, authority));
create table branch (deleted boolean not null, created_by_user_id bigint, created_date timestamp(6), id bigint generated by default as identity (start with 1), repository_id bigint not null, name varchar(255), primary key (id), constraint UK__BRANCH__REPOSITORY_ID__PATH unique (repository_id, name));
create table branch_notification (branch_id bigint not null, id bigint generated by default as identity (start with 1), new_msg_sent_at timestamp(6), screenshot_missing_msg_sent_at timestamp(6), translated_msg_sent_at timestamp(6), updated_msg_sent_at timestamp(6), content_md5 varchar(255), message_id varchar(255), notifier_id varchar(255), sender_type varchar(255), primary key (id), constraint UK__BRANCH_NOTIFICATION__BRANCH_ID__SENDER_TYPE unique (branch_id, sender_type));
create table branch_notifiers (branch_id bigint not null, notifiers varchar(255));
create table branch_statistic (branch_id bigint not null unique, created_date timestamp(6), for_translation_count bigint, id bigint generated by default as identity (start with 1), last_modified_date timestamp(6), total_count bigint, primary key (id));
create table branch_text_unit_statistic (branch_statistic_id bigint, for_translation_count bigint, id bigint generated by default as identity (start with 1), tm_text_unit_id bigint, total_count bigint, primary key (id), constraint UK__BTU_STAT__BTU_STAT_ID__TM_TEXT_UNIT_ID unique (branch_statistic_id, tm_text_unit_id));
create table "commit" (created_date timestamp(6), id bigint generated by default as identity (start with 1), last_modified_date timestamp(6), repository_id bigint, source_creation_date timestamp(6), author_email varchar(255), author_name varchar(255), name varchar(255), primary key (id), constraint UK__COMMIT__NAME_REPOSITORY_ID unique (name, repository_id));
