create table commit_to_push_run (commit_id bigint unique, created_date timestamp(6), id bigint generated by default as identity (start with 1), push_run_id bigint unique, primary key (id));
create table "drop" (canceled boolean, export_failed boolean, import_failed boolean, partially_imported boolean, created_by_user_id bigint, created_date timestamp(6), export_pollable_task_id bigint unique, id bigint generated by default as identity (start with 1), import_pollable_task_id bigint unique, last_imported_date timestamp(6), last_modified_date timestamp(6), repository_id bigint, drop_exporter_config text, drop_exporter_type varchar(255) check (drop_exporter_type in ('FILE_SYSTEM')), name varchar(255), primary key (id));
create table git_blame (created_date timestamp(6), id bigint generated by default as identity (start with 1), last_modified_date timestamp(6), tm_text_unit_id bigint not null, author_email varchar(255), author_name varchar(255), commit_name varchar(255), commit_time varchar(255), primary key (id), constraint UK__GIT_BLAME__TM_TEXT_UNIT_ID unique (tm_text_unit_id));
create table glossary (enabled boolean not null, priority integer not null, backing_repository_id bigint not null, created_date timestamp(6), id bigint generated by default as identity (start with 1), last_modified_date timestamp(6), scope_mode varchar(32) not null, description varchar(1024), asset_path varchar(255) not null, name varchar(255) not null, primary key (id), constraint UK__GLOSSARY__NAME unique (name));
create table glossary_excluded_repository (glossary_id bigint not null, repository_id bigint not null, constraint UK__GLOSSARY_EXCLUDED_REPOSITORY__GLOSSARY_REPOSITORY primary key (glossary_id, repository_id));
