create table repository_aud (checksla boolean, deleted boolean, hidden boolean, rev integer not null, revend integer, revtype smallint, created_by_user_id bigint, id bigint not null, manual_screenshot_run_id bigint, repository_statistic_id bigint, source_locale_id bigint, tm_id bigint, description varchar(255), drop_exporter_type varchar(255) check (drop_exporter_type in ('FILE_SYSTEM')), name varchar(255), primary key (rev, id));
