create table repository_statistic (created_by_user_id bigint, created_date timestamp(6), id bigint generated by default as identity (start with 1), last_modified_date timestamp(6), oosla_created_before timestamp(6), oosla_text_unit_count bigint, oosla_text_unit_word_count bigint, plural_text_unit_count bigint, plural_text_unit_word_count bigint, uncommented_text_unit_count bigint, unused_text_unit_count bigint, unused_text_unit_word_count bigint, used_text_unit_count bigint, used_text_unit_word_count bigint, primary key (id));
