create table review_project (text_unit_count integer not null, word_count integer not null, assigned_pm_user_id bigint, assigned_translator_user_id bigint, created_by_user_id bigint, created_date timestamp(6), decided_count bigint not null, due_date timestamp(6) not null, id bigint generated by default as identity (start with 1), last_modified_date timestamp(6), locale_id bigint not null, review_project_request_id bigint, team_id bigint, close_reason varchar(512), status varchar(255) not null check (status in ('OPEN','CLOSED')), terminology_phase varchar(255) check (terminology_phase in ('SPECIALIST_INPUT','PM_RESOLUTION')), type varchar(255) not null, primary key (id));
